import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    min_distance = float('inf')

    for i in range(len(unvisited_customers)):
        node = unvisited_customers[i]
        travel_time = np.linalg.norm(cur_truck_pos - node) / truck_speed
        arrival_time = current_time + travel_time

        if arrival_time <= time_windows[i][1] and arrival_time >= time_windows[i][0]:
            distance = np.linalg.norm(cur_truck_pos - node)
            if distance < min_distance:
                min_distance = distance
                best_node = i

    if best_node is None:
        min_distance = float('inf')
        for i in range(len(unvisited_customers)):
            node = unvisited_customers[i]
            distance = np.linalg.norm(cur_truck_pos - node)
            if distance < min_distance:
                min_distance = distance
                best_node = i

    return best_node
